import{_ as t,a as e,b as r,c as n}from"./chunks/下载好后的视频.pSSnkGgz.js";import{_ as i,o as l,c as d,a2 as o}from"./chunks/framework.DnrXFDHb.js";const f=JSON.parse('{"title":"نقل Magnet","description":"","frontmatter":{},"headers":[],"relativePath":"ar-SA/Other/magnet-transfer.md","filePath":"ar-SA/Other/magnet-transfer.md","lastUpdated":1781962217000}'),h={name:"ar-SA/Other/magnet-transfer.md"};function s(m,a,p,g,c,b){return l(),d("div",null,[...a[0]||(a[0]=[o('<h1 id="نقل-magnet" tabindex="-1">نقل Magnet <a class="header-anchor" href="#نقل-magnet" aria-label="Permalink to &quot;نقل Magnet&quot;">​</a></h1><p>يقوم Magnet transfer بتنزيل الملفات من magnet link ثم رفعها تلقائيًا إلى قناة التخزين السحابي التي تختارها.</p><p>يفيد في نقل حلقات الأنمي، والفيديوهات، والأرشيفات، والملفات المشابهة. الصق magnet link، وسيُنشئ ImgBed مهمة تنزيل في الخلفية. بعد انتهاء التنزيل يُرفع الملف إلى ImgBed ويظهر الرابط النهائي في قائمة الرفع.</p><p><img src="'+t+'" alt="Magnet transfer" loading="lazy"></p><h2 id="أين-تستخدمه؟" tabindex="-1">أين تستخدمه؟ <a class="header-anchor" href="#أين-تستخدمه؟" aria-label="Permalink to &quot;أين تستخدمه؟&quot;">​</a></h2><p>مدخل magnet transfer موجود في منطقة الرفع في الصفحة الرئيسية.</p><p>الصق magnet link في مربع الإدخال، واختر <code>Transfer</code>، ثم ارفع.</p><p><img src="'+e+'" alt="رفع أنمي" loading="lazy"></p><h2 id="قبل-أول-استخدام" tabindex="-1">قبل أول استخدام <a class="header-anchor" href="#قبل-أول-استخدام" aria-label="Permalink to &quot;قبل أول استخدام&quot;">​</a></h2><p>اضبط magnet transfer من لوحة الإدارة أولًا.</p><p>عادة تحتاج إلى:</p><ol><li>حساب GitHub لتشغيل مهمة التنزيل.</li><li>قناة رفع سحابية، مثل Google Drive أو OneDrive.</li><li>مجلد الرفع الهدف.</li><li>مهلة زمنية للمهمة.</li></ol><p>بعد جاهزية الإعدادات، ارجع إلى الصفحة الرئيسية والصق magnet link لبدء النقل.</p><h2 id="رفع-magnet-link" tabindex="-1">رفع Magnet Link <a class="header-anchor" href="#رفع-magnet-link" aria-label="Permalink to &quot;رفع Magnet Link&quot;">​</a></h2><ol><li>الصق magnet link في مربع الرفع في الصفحة الرئيسية.</li><li>تأكد أن الوضع مضبوط على <code>Transfer</code>.</li><li>اضغط upload.</li><li>انتظر حتى ينشئ ImgBed مهمة magnet.</li><li>بعد بدء المهمة، استخدم لوحة <code>Magnet Tasks</code> العائمة أسفل اليمين لمتابعة التقدم.</li></ol><p>قد يستغرق التنزيل والرفع وقتًا. السرعة تعتمد على مصدر magnet وبيئة GitHub runtime وقناة التخزين المختارة.</p><p><img src="'+r+'" alt="تنزيل magnet" loading="lazy"></p><h2 id="بعد-الاكتمال" tabindex="-1">بعد الاكتمال <a class="header-anchor" href="#بعد-الاكتمال" aria-label="Permalink to &quot;بعد الاكتمال&quot;">​</a></h2><p>بعد اكتمال المهمة تعرض قائمة الرفع اسم الملف والرابط.</p><p>الفيديوهات تعرض معاينة فيديو، والصور تعرض معاينة صورة، والملفات الأخرى تعرض أيقونة ملف عادية.</p><p><img src="'+n+'" alt="فيديو تم تنزيله" loading="lazy"></p><p>يمكنك نسخ:</p><table tabindex="0"><thead><tr><th>نوع الرابط</th><th>الاستخدام</th></tr></thead><tbody><tr><td>Original link</td><td>وصول مباشر للملف</td></tr><tr><td>Markdown</td><td>مقالات أو ملاحظات Markdown</td></tr><tr><td>HTML</td><td>كود صفحة ويب</td></tr><tr><td>BBCode</td><td>المنتديات التي تدعم BBCode</td></tr></tbody></table><h2 id="لوحة-magnet-task" tabindex="-1">لوحة Magnet Task <a class="header-anchor" href="#لوحة-magnet-task" aria-label="Permalink to &quot;لوحة Magnet Task&quot;">​</a></h2><p>تعرض لوحة مهام magnet أسفل اليمين عدد المهام واسم المهمة والتقدم والحالة النهائية.</p><p>حالات شائعة:</p><table tabindex="0"><thead><tr><th>الحالة</th><th>المعنى</th></tr></thead><tbody><tr><td>Waiting</td><td>تم إنشاء المهمة وتنتظر التشغيل.</td></tr><tr><td>Downloading</td><td>يتم تنزيل مورد magnet.</td></tr><tr><td>Uploading</td><td>اكتمل التنزيل ويتم رفع الملف إلى التخزين السحابي.</td></tr><tr><td>Completed</td><td>نجح الرفع ويمكن نسخ الرابط.</td></tr><tr><td>Failed</td><td>لم تكتمل المهمة بنجاح. راجع الرسالة وحاول مرة أخرى.</td></tr></tbody></table><h2 id="نصائح" tabindex="-1">نصائح <a class="header-anchor" href="#نصائح" aria-label="Permalink to &quot;نصائح&quot;">​</a></h2><ul><li>إذا كان magnet link يحتوي عدة ملفات، يعطي ImgBed الأولوية لعرض الملف الرئيسي المكتمل.</li><li>الملفات الكبيرة تستغرق وقتًا أطول. انتظر اكتمال المهمة قبل تحديث الصفحة.</li><li>إذا لم يكن لمورد magnet peers متاحون فقد يكون بطيئًا جدًا أو يفشل.</li><li>إذا نفدت حصة الحساب السحابي أو انتهى التفويض أو كان مجلد الرفع خاطئًا، قد تفشل المهمة.</li><li>قد تحتاج معاينة الفيديو إلى ثوانٍ بعد اكتمال الرفع.</li></ul><h2 id="faq" tabindex="-1">FAQ <a class="header-anchor" href="#faq" aria-label="Permalink to &quot;FAQ&quot;">​</a></h2><h3 id="لا-يبدأ-شيء-بعد-لصق-magnet-link" tabindex="-1">لا يبدأ شيء بعد لصق Magnet Link <a class="header-anchor" href="#لا-يبدأ-شيء-بعد-لصق-magnet-link" aria-label="Permalink to &quot;لا يبدأ شيء بعد لصق Magnet Link&quot;">​</a></h3><p>تأكد أن magnet transfer مفعّل في لوحة الإدارة، وأن حساب GitHub وقناة السحابة المحددين صالحان.</p><h3 id="التنزيل-بطيء-دائمًا" tabindex="-1">التنزيل بطيء دائمًا <a class="header-anchor" href="#التنزيل-بطيء-دائمًا" aria-label="Permalink to &quot;التنزيل بطيء دائمًا&quot;">​</a></h3><p>سرعة magnet تعتمد على المورد نفسه. إذا لم توجد peers متاحة فقد يكون التنزيل بطيئًا جدًا أو غير ممكن.</p><h3 id="لا-تظهر-معاينة-بعد-الرفع" tabindex="-1">لا تظهر معاينة بعد الرفع <a class="header-anchor" href="#لا-تظهر-معاينة-بعد-الرفع" aria-label="Permalink to &quot;لا تظهر معاينة بعد الرفع&quot;">​</a></h3><p>تأكد أولًا أن رابط الملف يفتح. قد تحتاج ملفات الفيديو إلى وقت قصير للتحميل في المتصفح، أو يمكنك فتح الرابط مباشرة.</p><h3 id="ماذا-أفحص-إذا-فشلت-المهمة؟" tabindex="-1">ماذا أفحص إذا فشلت المهمة؟ <a class="header-anchor" href="#ماذا-أفحص-إذا-فشلت-المهمة؟" aria-label="Permalink to &quot;ماذا أفحص إذا فشلت المهمة؟&quot;">​</a></h3><p>تحقق أن magnet link صالح، وأن القناة السحابية تعمل، وأن مجلد الرفع صحيح. ثم أرسل المهمة مرة أخرى.</p>',38)])])}const _=i(h,[["render",s]]);export{f as __pageData,_ as default};
